import{_ as e,c as a,o as n,ag as s}from"./chunks/framework.C86mscM5.js";const h=JSON.parse('{"title":"difference between properties and attributes","description":"","frontmatter":{},"headers":[],"relativePath":"fundamentals/js/dom/difference-between-properties-and-attributes.md","filePath":"fundamentals/js/dom/difference-between-properties-and-attributes.md","lastUpdated":1761728626000}'),d={name:"fundamentals/js/dom/difference-between-properties-and-attributes.md"};function r(o,t,c,p,i,l){return n(),a("div",null,t[0]||(t[0]=[s(`<h1 id="difference-between-properties-and-attributes" tabindex="-1">difference between properties and attributes <a class="header-anchor" href="#difference-between-properties-and-attributes" aria-label="Permalink to &quot;difference between properties and attributes&quot;">​</a></h1><h2 id="🧩-一、基本定义对比" tabindex="-1">🧩 一、基本定义对比 <a class="header-anchor" href="#🧩-一、基本定义对比" aria-label="Permalink to &quot;🧩 一、基本定义对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比点</th><th><strong>Attribute（HTML 属性）</strong></th><th><strong>Property（DOM 属性）</strong></th></tr></thead><tbody><tr><td>定义位置</td><td>定义在 HTML 标签上</td><td>定义在 DOM 对象上（JS 层）</td></tr><tr><td>存在形式</td><td>字符串存在于 HTML 源代码中</td><td>JS 对象的属性，可能是各种类型</td></tr><tr><td>访问方式</td><td><code>element.getAttribute()</code> / <code>element.setAttribute()</code></td><td>直接通过对象访问：<code>element.property</code></td></tr><tr><td>数据类型</td><td>总是字符串</td><td>可以是任意类型（boolean、number、object…）</td></tr><tr><td>同步机制</td><td>初始时同步到 property（一次性）</td><td>修改 property 不一定影响 attribute</td></tr><tr><td>作用范围</td><td>仅影响 HTML 标记层</td><td>影响页面实际行为和渲染</td></tr></tbody></table><hr><h2 id="🧠-二、例子说明差异" tabindex="-1">🧠 二、例子说明差异 <a class="header-anchor" href="#🧠-二、例子说明差异" aria-label="Permalink to &quot;🧠 二、例子说明差异&quot;">​</a></h2><h3 id="例1-input-的-value" tabindex="-1">例1：<code>input</code> 的 <code>value</code> <a class="header-anchor" href="#例1-input-的-value" aria-label="Permalink to &quot;例1：\`input\` 的 \`value\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;input id=&quot;username&quot; value=&quot;Lee&quot;&gt;</span></span>
<span class="line"><span>const input = document.getElementById(&#39;username&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Attribute：HTML 初始值</span></span>
<span class="line"><span>console.log(input.getAttribute(&#39;value&#39;)); // &quot;Lee&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Property：当前运行时值（可能被用户修改）</span></span>
<span class="line"><span>console.log(input.value); // &quot;Lee&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 修改 property</span></span>
<span class="line"><span>input.value = &quot;Tom&quot;;</span></span>
<span class="line"><span>console.log(input.getAttribute(&#39;value&#39;)); // 仍然是 &quot;Lee&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 修改 attribute</span></span>
<span class="line"><span>input.setAttribute(&#39;value&#39;, &#39;Mike&#39;);</span></span>
<span class="line"><span>console.log(input.value); // 仍然是 &quot;Tom&quot;（不会立刻更新）</span></span></code></pre></div><p>✅ <strong>结论</strong>：</p><ul><li><code>attribute</code> 是 <strong>初始值</strong></li><li><code>property</code> 是 <strong>实时状态</strong></li></ul><hr><h3 id="例2-checked" tabindex="-1">例2：<code>checked</code> <a class="header-anchor" href="#例2-checked" aria-label="Permalink to &quot;例2：\`checked\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;input type=&quot;checkbox&quot; id=&quot;agree&quot; checked&gt;</span></span>
<span class="line"><span>const checkbox = document.getElementById(&#39;agree&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 初始属性</span></span>
<span class="line"><span>console.log(checkbox.getAttribute(&#39;checked&#39;)); // &quot;&quot;</span></span>
<span class="line"><span>console.log(checkbox.checked); // true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 改变 property</span></span>
<span class="line"><span>checkbox.checked = false;</span></span>
<span class="line"><span>console.log(checkbox.getAttribute(&#39;checked&#39;)); // 依旧是 &quot;&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>checkbox.setAttribute(&#39;checked&#39;, &#39;&#39;); // 改变 attribute</span></span>
<span class="line"><span>console.log(checkbox.checked); // true</span></span></code></pre></div><p>✅ <strong>结论</strong>： <code>checked</code> 属性（HTML）代表<strong>默认是否选中</strong>， 而 <code>checked</code> property（DOM）代表<strong>当前状态</strong>。</p><hr><h2 id="⚙️-三、同步关系总结" tabindex="-1">⚙️ 三、同步关系总结 <a class="header-anchor" href="#⚙️-三、同步关系总结" aria-label="Permalink to &quot;⚙️ 三、同步关系总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>Attribute → Property</th><th>Property → Attribute</th></tr></thead><tbody><tr><td>初始加载</td><td>✅ 是（HTML → DOM）</td><td>❌ 否</td></tr><tr><td>修改 HTML Attribute</td><td>✅ 会更新部分 Property（如 src, href, id）</td><td>—</td></tr><tr><td>修改 DOM Property</td><td>❌ 通常不会反映到 Attribute</td><td>—</td></tr></tbody></table><hr><h2 id="💡-四、开发中建议" tabindex="-1">💡 四、开发中建议 <a class="header-anchor" href="#💡-四、开发中建议" aria-label="Permalink to &quot;💡 四、开发中建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目的</th><th>使用</th></tr></thead><tbody><tr><td>想操作 HTML 原始定义（比如序列化）</td><td><code>getAttribute()</code> / <code>setAttribute()</code></td></tr><tr><td>想控制页面行为或状态</td><td>直接改 DOM property</td></tr></tbody></table><hr><h2 id="🧭-五、常见属性同步行为对比表" tabindex="-1">🧭 五、常见属性同步行为对比表 <a class="header-anchor" href="#🧭-五、常见属性同步行为对比表" aria-label="Permalink to &quot;🧭 五、常见属性同步行为对比表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>元素</th><th>Attribute</th><th>Property</th><th>是否自动同步</th></tr></thead><tbody><tr><td><code>&lt;input value&gt;</code></td><td><code>getAttribute(&#39;value&#39;)</code></td><td><code>.value</code></td><td>❌</td></tr><tr><td><code>&lt;input checked&gt;</code></td><td><code>getAttribute(&#39;checked&#39;)</code></td><td><code>.checked</code></td><td>❌</td></tr><tr><td><code>&lt;img src&gt;</code></td><td><code>getAttribute(&#39;src&#39;)</code></td><td><code>.src</code></td><td>✅</td></tr><tr><td><code>&lt;a href&gt;</code></td><td><code>getAttribute(&#39;href&#39;)</code></td><td><code>.href</code>（绝对路径）</td><td>✅</td></tr><tr><td><code>&lt;div id&gt;</code></td><td><code>getAttribute(&#39;id&#39;)</code></td><td><code>.id</code></td><td>✅</td></tr><tr><td><code>&lt;option selected&gt;</code></td><td><code>getAttribute(&#39;selected&#39;)</code></td><td><code>.selected</code></td><td>❌</td></tr></tbody></table><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li>see the <a href="https://stackoverflow.com/questions/6003819/what-is-the-difference-between-properties-and-attributes-in-html#answer-6004028" target="_blank" rel="nofollow noopener noreferrer">answer</a></li></ul>`,24)]))}const b=e(d,[["render",r]]);export{h as __pageData,b as default};
